import numpy as np

def gate_matrix(name, params=()):
    """Get 2x2 matrix for a gate (provided)."""
    if name == 'H':
        return np.array([[1, 1], [1, -1]], dtype=complex) / np.sqrt(2)
    elif name == 'X':
        return np.array([[0, 1], [1, 0]], dtype=complex)
    elif name == 'Z':
        return np.array([[1, 0], [0, -1]], dtype=complex)
    elif name == 'T':
        return np.array([[1, 0], [0, np.exp(1j * np.pi / 4)]], dtype=complex)
    elif name == 'RZ':
        theta = params[0]
        return np.array([[np.exp(-1j*theta/2), 0], [0, np.exp(1j*theta/2)]], dtype=complex)
    return np.eye(2, dtype=complex)

def combined_unitary(gates):
    """
    Compute the combined unitary of a gate sequence.

    Args:
        gates: List of (name, params) tuples
    Returns:
        2x2 numpy array representing combined unitary
    """
    # Start with identity
    U = np.eye(2, dtype=complex)

    # Gates apply left-to-right: |psi'> = G_n ... G_2 G_1 |psi>
    # So we multiply: U = G_n @ G_{n-1} @ ... @ G_1
    # Process in order, each new gate multiplies from the left
    for name, params in gates:
        G = gate_matrix(name, params)
        U = G @ U

    return U

# Test: H-H should be identity
gates = [('H', ()), ('H', ())]
U = combined_unitary(gates)
print(np.allclose(U, np.eye(2)))  # True

