import numpy as np

def gate_matrix(name, params=()):
    if name == 'H':
        return np.array([[1, 1], [1, -1]], dtype=complex) / np.sqrt(2)
    elif name == 'X':
        return np.array([[0, 1], [1, 0]], dtype=complex)
    elif name == 'T':
        return np.array([[1, 0], [0, np.exp(1j * np.pi / 4)]], dtype=complex)
    elif name == 'S':
        return np.array([[1, 0], [0, 1j]], dtype=complex)
    elif name == 'Z':
        return np.array([[1, 0], [0, -1]], dtype=complex)
    return np.eye(2, dtype=complex)

def is_identity(U, tolerance=1e-10):
    phase = U[0, 0]
    if abs(abs(phase) - 1) > tolerance:
        return False
    return np.allclose(U / phase, np.eye(2), atol=tolerance)

def combined_unitary(gates):
    U = np.eye(2, dtype=complex)
    for name, _ in gates:
        U = gate_matrix(name) @ U
    return U

def peephole_optimize(gates):
    """
    Single-qubit peephole optimization.

    Args:
        gates: List of (name, qubit) tuples
    Returns:
        Optimized gate list
    """
    result = []
    i = 0

    while i < len(gates):
        name, qubit = gates[i]

        # Collect consecutive single-qubit gates on same qubit
        window = [(name, qubit)]
        j = i + 1

        while j < len(gates) and gates[j][1] == qubit:
            window.append(gates[j])
            j += 1

        if len(window) > 1:
            # Compute combined unitary
            U = combined_unitary(window)

            if is_identity(U):
                # Skip all gates in window (they cancel)
                pass
            else:
                # Keep original for now (full implementation would resynthesize)
                result.extend(window)
        else:
            result.append(gates[i])

        i = j

    return result

# Test: H-T-T-H should optimize
gates = [('H', 0), ('T', 0), ('T', 0), ('H', 0)]
print(peephole_optimize(gates))
